<?php
namespace App\Domain\Equipment\Data;
final class ItemStatBonuses{private $values;public function __construct($maxHealth=0,$attack=0,$defense=0,$accuracy=0,$evasion=0,$criticalChance=0,$attackSpeed=0){$this->values=['max_health'=>(int)$maxHealth,'attack'=>(int)$attack,'defense'=>(int)$defense,'accuracy'=>(int)$accuracy,'evasion'=>(int)$evasion,'critical_chance'=>(float)$criticalChance,'attack_speed'=>(float)$attackSpeed];}public function maxHealth(){return$this->values['max_health'];}public function attack(){return$this->values['attack'];}public function defense(){return$this->values['defense'];}public function accuracy(){return$this->values['accuracy'];}public function evasion(){return$this->values['evasion'];}public function criticalChance(){return$this->values['critical_chance'];}public function attackSpeed(){return$this->values['attack_speed'];}public function hasAny(){foreach($this->values as $value)if($value!=0)return true;return false;}public function toArray(){return array_merge([],$this->values);}}
